<!doctype html><html lang="en-AU"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Trailer marketplace | TrailerWise</title><meta name="description" content="Browse active Australian trailer listings from TrailerWise providers."><style>*{box-sizing:border-box}body{margin:0;background:#faf5ff;color:#2e1065;font:16px/1.5 system-ui,sans-serif}main{max-width:75rem;margin:auto;padding:2rem 1rem 5rem}a{color:#6d28d9}h1{font-size:clamp(2.5rem,8vw,5rem);margin:.5rem 0}.filters{background:#fff;padding:1rem;border-radius:.7rem;margin:1rem 0}select,button{padding:.7rem;font:inherit}.grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(16rem,1fr));gap:1rem}.card{background:#fff;padding:1.2rem;border-radius:.7rem;border-top:.35rem solid #7c3aed}.card a{font-weight:800;font-size:1.1rem}.empty{background:#fff;padding:2rem;border-radius:.7rem}</style></head><body><main><a href="<?= e(url('/')) ?>">← TrailerWise home</a><h1>Trailer marketplace</h1><p>Active listings from approved TrailerWise businesses.</p><form class="filters" method="get"><label for="type">Trailer type</label> <select id="type" name="type"><option value="">All types</option><?php foreach($types as $item): ?><option value="<?= e($item['slug']) ?>" <?= $type===$item['slug']?'selected':'' ?>><?= e($item['name']) ?></option><?php endforeach; ?></select> <button>Filter</button></form><?php if(!$listings): ?><div class="empty"><h2>No active listings yet</h2><p>The marketplace is ready; approved providers can publish listings once onboarding opens.</p></div><?php else: ?><div class="grid"><?php foreach($listings as $listing): ?><article class="card"><p><?= e($listing['trailer_type']) ?> · <?= e(ucfirst($listing['listing_kind'])) ?></p><h2><a href="<?= e(url('/marketplace/'.$listing['slug'])) ?>"><?= e($listing['title']) ?></a></h2><p><?= e($listing['provider_name']) ?></p><?php if($listing['price_aud_cents']!==null): ?><strong>$<?= e(number_format(((int)$listing['price_aud_cents'])/100,2)) ?> AUD</strong><?php endif; ?></article><?php endforeach; ?></div><?php endif; ?></main></body></html>
